{
  "name": "Global Import Calculator",
  "description": "Calculate the landed cost of imported products from USD or CNY to KRW, including forwarding, logistics, and additional fees, using real-time exchange rates."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Currency {
  USD = 'USD',
  CNY = 'CNY'
}

export interface ExchangeRates {
  USD: number;
  CNY: number;
}

export interface CostBreakdown {
  baseAmountForeign: number;
  baseAmountKRW: number;
  forwardingFee: number; // 10%
  logisticsFee: number; // 25%
  additionalCost: number;
  totalCostKRW: number;
  unitCostKRW: number;
}

export interface GroundingSource {
  title: string;
  uri: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExchangeRates, GroundingSource } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

interface ExchangeRateResponse {
  rates: ExchangeRates;
  sources: GroundingSource[];
}

export const fetchCurrentExchangeRates = async (): Promise<ExchangeRateResponse> => {
  try {
    const modelId = "gemini-2.5-flash"; // Good for search and data extraction

    // We want real data, so we use Google Search grounding.
    const response = await ai.models.generateContent({
      model: modelId,
      contents: "What is the current exchange rate for 1 USD to KRW and 1 CNY to KRW today? accurate value based on Naver Finance or Google Finance.",
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            USD: { type: Type.NUMBER, description: "Current exchange rate for 1 USD in KRW" },
            CNY: { type: Type.NUMBER, description: "Current exchange rate for 1 CNY in KRW" }
          },
          required: ["USD", "CNY"]
        }
      }
    });

    const sources: GroundingSource[] = [];

    // Extract grounding chunks for sources
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach(chunk => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title || "Web Source",
            uri: chunk.web.uri || "#"
          });
        }
      });
    }

    let rates: ExchangeRates = { USD: 1400, CNY: 195 }; // Fallback defaults

    try {
      if (response.text) {
        const parsed = JSON.parse(response.text);
        if (parsed.USD && parsed.CNY) {
          rates = {
            USD: parsed.USD,
            CNY: parsed.CNY
          };
        }
      }
    } catch (e) {
      console.warn("Failed to parse JSON response from Gemini, using fallback or regex extraction might be needed.", e);
    }

    return { rates, sources };

  } catch (error) {
    console.error("Error fetching exchange rates:", error);
    // Return fallback values if API fails
    return {
      rates: { USD: 1400, CNY: 195 },
      sources: []
    };
  }
};

import React, { useState } from 'react';
import { Info } from 'lucide-react';

interface InfoTooltipProps {
  content: string;
}

const InfoTooltip: React.FC<InfoTooltipProps> = ({ content }) => {
  const [isVisible, setIsVisible] = useState(false);

  return (
    <div className="relative inline-block ml-2">
      <button 
        className="text-gray-400 hover:text-gray-600 transition-colors focus:outline-none"
        onMouseEnter={() => setIsVisible(true)}
        onMouseLeave={() => setIsVisible(false)}
        onClick={() => setIsVisible(!isVisible)}
        aria-label="Information"
      >
        <Info size={16} />
      </button>
      {isVisible && (
        <div className="absolute z-10 w-64 p-2 mt-2 -ml-32 text-xs text-white bg-gray-800 rounded-lg shadow-lg left-1/2 opacity-100 transition-opacity">
          {content}
          <div className="absolute -top-1 left-1/2 w-2 h-2 -ml-1 bg-gray-800 transform rotate-45"></div>
        </div>
      )}
    </div>
  );
};

export default InfoTooltip;

import React, { useState, useEffect } from 'react';
import { X, Plus, Trash2 } from 'lucide-react';

interface AdditionalCostItem {
  id: string;
  name: string;
  amount: number;
}

interface AdditionalCostModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (total: number) => void;
  currentTotal: number;
}

const AdditionalCostModal: React.FC<AdditionalCostModalProps> = ({ isOpen, onClose, onSave, currentTotal }) => {
  const [items, setItems] = useState<AdditionalCostItem[]>([]);
  const [newItemName, setNewItemName] = useState('');
  const [newItemAmount, setNewItemAmount] = useState('');

  // Initialize with a default item if logic required, or just keep it clean
  useEffect(() => {
    if (currentTotal > 0 && items.length === 0) {
      // If we have a total coming in but no items, maybe represent it as "Previous Total"
      // But for this app, we manage state purely here when open. 
      // Simplified: We assume user re-enters or we could persist detailed items in parent.
      // For this implementation, we will just start with one item if total > 0.
      if (currentTotal > 0) {
        setItems([{ id: 'existing', name: '기타 비용 합계', amount: currentTotal }]);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);

  if (!isOpen) return null;

  const handleAddItem = () => {
    if (!newItemName || !newItemAmount) return;
    const amount = parseFloat(newItemAmount);
    if (isNaN(amount)) return;

    setItems([...items, { id: Date.now().toString(), name: newItemName, amount }]);
    setNewItemName('');
    setNewItemAmount('');
  };

  const handleRemoveItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const calculateTotal = () => items.reduce((sum, item) => sum + item.amount, 0);

  const handleConfirm = () => {
    onSave(calculateTotal());
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in-up">
        <div className="px-6 py-4 bg-gray-50 border-b flex justify-between items-center">
          <h3 className="font-semibold text-gray-800">추가 비용 입력</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-4">
          <div className="space-y-3">
            <p className="text-sm text-gray-600">
              식품검사비, 전기안전비용 등 별도로 발생하는 비용을 입력해주세요. (원화 기준)
            </p>

            {/* Input Row */}
            <div className="flex gap-2">
              <input
                type="text"
                placeholder="항목명 (예: 정밀검사비)"
                className="flex-1 px-3 py-2 border rounded-lg focus:ring-2 focus:ring-primary-500 outline-none text-sm"
                value={newItemName}
                onChange={(e) => setNewItemName(e.target.value)}
              />
              <input
                type="number"
                placeholder="금액 (원)"
                className="w-32 px-3 py-2 border rounded-lg focus:ring-2 focus:ring-primary-500 outline-none text-sm text-right"
                value={newItemAmount}
                onChange={(e) => setNewItemAmount(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
              />
              <button 
                onClick={handleAddItem}
                className="bg-primary-600 text-white p-2 rounded-lg hover:bg-primary-700 transition-colors"
              >
                <Plus size={20} />
              </button>
            </div>

            {/* List */}
            <div className="mt-4 max-h-48 overflow-y-auto space-y-2">
              {items.length === 0 ? (
                <div className="text-center py-4 text-gray-400 text-sm border-2 border-dashed rounded-lg">
                  추가된 비용이 없습니다.
                </div>
              ) : (
                items.map(item => (
                  <div key={item.id} className="flex justify-between items-center bg-gray-50 p-2 rounded border">
                    <span className="text-sm text-gray-700">{item.name}</span>
                    <div className="flex items-center gap-3">
                      <span className="text-sm font-medium text-gray-900">₩{item.amount.toLocaleString()}</span>
                      <button onClick={() => handleRemoveItem(item.id)} className="text-red-400 hover:text-red-600">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        <div className="px-6 py-4 bg-gray-50 border-t flex justify-between items-center">
          <div className="text-sm">
            <span className="text-gray-500">총 추가비용: </span>
            <span className="font-bold text-primary-700 text-lg">₩{calculateTotal().toLocaleString()}</span>
          </div>
          <button 
            onClick={handleConfirm}
            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 font-medium transition-colors"
          >
            적용하기
          </button>
        </div>
      </div>
    </div>
  );
};

export default AdditionalCostModal;

import React, { useState, useEffect, useMemo } from 'react';
import { fetchCurrentExchangeRates } from './services/geminiService';
import { Currency, ExchangeRates, CostBreakdown, GroundingSource } from './types';
import { Calculator, RefreshCw, DollarSign, Box, PlusCircle, ExternalLink, ArrowRight } from 'lucide-react';
import InfoTooltip from './components/InfoTooltip';
import AdditionalCostModal from './components/AdditionalCostModal';

const App: React.FC = () => {
  const [rates, setRates] = useState<ExchangeRates>({ USD: 0, CNY: 0 });
  const [loadingRates, setLoadingRates] = useState<boolean>(true);
  const [rateSources, setRateSources] = useState<GroundingSource[]>([]);

  const [currency, setCurrency] = useState<Currency>(Currency.USD);
  const [productCost, setProductCost] = useState<string>('');
  const [quantity, setQuantity] = useState<string>('1');
  const [additionalCost, setAdditionalCost] = useState<number>(0);

  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);

  // Initial Data Fetch
  useEffect(() => {
    loadRates();
  }, []);

  const loadRates = async () => {
    setLoadingRates(true);
    const data = await fetchCurrentExchangeRates();
    setRates(data.rates);
    setRateSources(data.sources);
    setLoadingRates(false);
  };

  // Calculation Logic
  const breakdown: CostBreakdown = useMemo(() => {
    const cost = parseFloat(productCost) || 0;
    const qty = parseInt(quantity) || 0;
    const rate = currency === Currency.USD ? rates.USD : rates.CNY;

    if (cost === 0 || qty === 0 || rate === 0) {
      return {
        baseAmountForeign: 0,
        baseAmountKRW: 0,
        forwardingFee: 0,
        logisticsFee: 0,
        additionalCost: 0,
        totalCostKRW: 0,
        unitCostKRW: 0
      };
    }

    const baseAmountForeign = cost * qty;
    const baseAmountKRW = baseAmountForeign * rate;

    // Logic from prompt: Forwarding 10%, Logistics/Customs 25%
    const forwardingFee = baseAmountKRW * 0.10;
    const logisticsFee = baseAmountKRW * 0.25;

    const totalCostKRW = baseAmountKRW + forwardingFee + logisticsFee + additionalCost;
    const unitCostKRW = totalCostKRW / qty;

    return {
      baseAmountForeign,
      baseAmountKRW,
      forwardingFee,
      logisticsFee,
      additionalCost,
      totalCostKRW,
      unitCostKRW
    };
  }, [productCost, quantity, currency, rates, additionalCost]);

  const currencySymbol = currency === Currency.USD ? '$' : '¥';

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans selection:bg-primary-200">

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-primary-600 text-white p-2 rounded-lg shadow-sm">
              <Calculator size={20} />
            </div>
            <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-primary-700 to-primary-500">
              수입 원가 계산기
            </h1>
          </div>

          <div className="flex items-center gap-4 text-sm">
            <div className="hidden sm:flex items-center gap-2 text-gray-500 bg-gray-100 px-3 py-1 rounded-full">
              <span className={`w-2 h-2 rounded-full ${loadingRates ? 'bg-yellow-400 animate-pulse' : 'bg-green-500'}`}></span>
              {loadingRates ? '환율 조회 중...' : '환율 적용 완료'}
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Exchange Rate Banner */}
        <div className="mb-8 bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex flex-col sm:flex-row gap-6 w-full">
             <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center text-blue-600 font-bold border border-blue-100">
                  $
                </div>
                <div>
                  <p className="text-xs text-gray-500 font-medium">USD 환율 (1달러)</p>
                  <p className="text-lg font-bold text-gray-900">
                    {loadingRates ? '...' : `₩${rates.USD.toLocaleString(undefined, { maximumFractionDigits: 2 })}`}
                  </p>
                </div>
             </div>
             <div className="w-px h-10 bg-gray-200 hidden sm:block"></div>
             <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-red-50 flex items-center justify-center text-red-600 font-bold border border-red-100">
                  ¥
                </div>
                <div>
                  <p className="text-xs text-gray-500 font-medium">CNY 환율 (1위안)</p>
                  <p className="text-lg font-bold text-gray-900">
                    {loadingRates ? '...' : `₩${rates.CNY.toLocaleString(undefined, { maximumFractionDigits: 2 })}`}
                  </p>
                </div>
             </div>
          </div>
          <button 
            onClick={loadRates}
            disabled={loadingRates}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-primary-700 bg-primary-50 rounded-lg hover:bg-primary-100 transition-colors disabled:opacity-50 whitespace-nowrap"
          >
            <RefreshCw size={16} className={loadingRates ? "animate-spin" : ""} />
            환율 새로고침
          </button>
        </div>

        {/* Source Links */}
        {!loadingRates && rateSources.length > 0 && (
          <div className="mb-4 flex flex-wrap gap-2">
             <span className="text-xs text-gray-500 self-center">환율 출처:</span>
             {rateSources.map((source, idx) => (
