              </ul>
            </div>
          </section>

          {/* Result Section */}
          <section className="lg:col-span-7">
            <div className="bg-white rounded-2xl shadow-lg border border-gray-200 overflow-hidden sticky top-24">
              <div className="bg-gray-900 text-white p-6">
                <h2 className="text-lg font-medium text-gray-300 mb-1">최종 개당 원가</h2>
                <div className="flex items-baseline gap-2">
                  <span className="text-4xl font-bold tracking-tight">
                    ₩ {breakdown.unitCostKRW.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                  </span>
                  <span className="text-gray-400">/ 개</span>
                </div>
              </div>

              <div className="p-6">
                <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-4">비용 상세 분석</h3>

                <div className="space-y-4">
                  {/* Base Cost */}
