                        {currencySymbol} {breakdown.baseAmountForeign.toLocaleString()} × 환율
                      </span>
                    </div>
                    <span className="font-semibold text-gray-900">₩ {breakdown.baseAmountKRW.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
