                      <span className="ml-2 text-xs font-bold text-indigo-600 bg-indigo-100 px-2 py-0.5 rounded-full">25%</span>
                    </div>
                    <span className="font-semibold text-gray-900">+ ₩ {breakdown.logisticsFee.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
                  </div>

                  {/* Additional Costs */}
                  <div className="flex justify-between items-center py-2 border-b border-gray-100">
                    <div className="flex items-center">
                      <span className="text-gray-600 font-medium">기타 추가 비용</span>
                      {additionalCost > 0 && (
                         <span className="ml-2 text-xs text-gray-400">(검사비 등)</span>
                      )}
                    </div>
                    <span className="font-semibold text-gray-900">{additionalCost > 0 ? '+ ' : ''}₩ {breakdown.additionalCost.toLocaleString()}</span>
                  </div>
                </div>

                {/* Total Summary */}
                <div className="mt-8 bg-gray-50 rounded-xl p-5 border border-gray-200">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-gray-500 font-medium">총 지출 예상 금액</span>
                    <span className="text-xl font-bold text-gray-800">₩ {breakdown.totalCostKRW.toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
