import React, { useState, useEffect, useMemo } from 'react';
import { fetchCurrentExchangeRates } from './services/geminiService';
import { Currency, ExchangeRates, CostBreakdown, GroundingSource } from './types';
import { Calculator, RefreshCw, DollarSign, Box, PlusCircle, ExternalLink, TrendingUp, Store, ShoppingBag, Coins } from 'lucide-react';
import InfoTooltip from './components/InfoTooltip';
import AdditionalCostModal from './components/AdditionalCostModal';

const App: React.FC = () => {
  const [rates, setRates] = useState<ExchangeRates>({ USD: 0, CNY: 0 });
  const [loadingRates, setLoadingRates] = useState<boolean>(true);
  const [rateSources, setRateSources] = useState<GroundingSource[]>([]);

  const [currency, setCurrency] = useState<Currency>(Currency.USD);
  const [productCost, setProductCost] = useState<string>('');
  const [quantity, setQuantity] = useState<string>('1');
  const [additionalCost, setAdditionalCost] = useState<number>(0);

  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);

  // Initial Data Fetch
  useEffect(() => {
    loadRates();
  }, []);

  const loadRates = async () => {
    setLoadingRates(true);
    const data = await fetchCurrentExchangeRates();
    setRates(data.rates);
    setRateSources(data.sources);
    setLoadingRates(false);
  };

  // Calculation Logic
  const breakdown: CostBreakdown = useMemo(() => {
    const cost = parseFloat(productCost) || 0;
    const qty = parseInt(quantity) || 0;
    const rate = currency === Currency.USD ? rates.USD : rates.CNY;

    if (cost === 0 || qty === 0 || rate === 0) {
      return {
        baseAmountForeign: 0,
        baseAmountKRW: 0,
        forwardingFee: 0,
        logisticsFee: 0,
        additionalCost: 0,
        totalCostKRW: 0,
        unitCostKRW: 0
      };
    }

    const rawBaseForeign = cost * qty;

    // Hidden Fee Logic (CNY based)
    // 1000 or less: 300 CNY, 5000 or less: 600 CNY, Over 5000: 800 CNY
    let hiddenFeeCNY = 0;
    if (qty <= 1000) {
      hiddenFeeCNY = 300;
    } else if (qty <= 5000) {
      hiddenFeeCNY = 600;
    } else {
      hiddenFeeCNY = 800;
    }

    // Convert hidden fee to KRW (Always use CNY rate for this fee)
    const hiddenFeeKRW = hiddenFeeCNY * rates.CNY;

    // Base Amount in KRW includes the hidden fee invisibly
    const baseAmountKRW = (rawBaseForeign * rate) + hiddenFeeKRW;

    // Logic from prompt: Forwarding 10%, Logistics/Customs 25% of the Base Amount
    const forwardingFee = baseAmountKRW * 0.10;
    const logisticsFee = baseAmountKRW * 0.25;

    const totalCostKRW = baseAmountKRW + forwardingFee + logisticsFee + additionalCost;
    const unitCostKRW = totalCostKRW / qty;

    return {
      baseAmountForeign: rawBaseForeign,
      baseAmountKRW,
      forwardingFee,
      logisticsFee,
      additionalCost,
      totalCostKRW,
      unitCostKRW
    };
  }, [productCost, quantity, currency, rates, additionalCost]);

  // Selling Price Logic
  const sellingPrice = useMemo(() => {
    const qty = parseInt(quantity) || 0;
    const vatIncludedUnitCost = breakdown.unitCostKRW * 1.1; // VAT 10% included

    // Wholesale: VAT Included Price + Margin 10%
    // Profit part is just the margin: VatIncludedCost * 0.10
    const wholesalePrice = vatIncludedUnitCost * 1.10;
    const wholesaleProfitPerUnit = vatIncludedUnitCost * 0.10;
    const wholesaleTotalProfit = wholesaleProfitPerUnit * qty;

    // Retail: VAT Included Price + Fee 12% + Margin 13%
    // Price = Base * (1 + 0.12 + 0.13)
    // Profit part is the margin: VatIncludedCost * 0.13
    const retailPrice = vatIncludedUnitCost * (1 + 0.12 + 0.13);
    const retailProfitPerUnit = vatIncludedUnitCost * 0.13;
    const retailTotalProfit = retailProfitPerUnit * qty;

    return {
      vatIncludedUnitCost,
      wholesalePrice,
      wholesaleTotalProfit,
      retailPrice,
      retailTotalProfit
    };
  }, [breakdown.unitCostKRW, quantity]);

  const currencySymbol = currency === Currency.USD ? '$' : '¥';

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans selection:bg-primary-200">

