               <div className="bg-indigo-50/50 px-6 py-3 text-xs text-indigo-700 flex items-center gap-2 border-t border-indigo-100">
                  <InfoTooltip content="도매가는 부가세 포함 원가에 10% 마진을, 소매가는 수수료 12%와 마진 13%를 더한 금액입니다." />
                  <span>모든 판매가는 부가세 10%가 포함된 원가를 기준으로 계산됩니다.</span>
               </div>
            </div>

            <div className="flex justify-center print:hidden">
              <button onClick={() => window.print()} className="text-sm text-gray-500 hover:text-gray-900 flex items-center gap-2">
                <ExternalLink size={14} /> 결과 인쇄 / PDF 저장
              </button>
            </div>

          </section>
        </div>
      </main>

      <AdditionalCostModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={setAdditionalCost}
        currentTotal={additionalCost}
      />

    </div>
  );
};

export default App;
